import { createClient } from '@supabase/supabase-js';
import { LexicalEntry, UserProfile, Language } from '../types';

const supabaseUrl = 'https://pfykbgifzgfgeuiadebm.supabase.co';
const supabaseAnonKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InBmeWtiZ2lmemdmZ2V1aWFkZWJtIiwicm9sZSI6ImFub24iLCJpYXQiOjE3Njc0NTY5ODMsImV4cCI6MjA4MzAzMjk4M30.tSh8OgqVw3yk4JgCs7jzz21SJLKaotce_8AVAJdi9Z0';

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

/**
 * SessionArchive: A robust in-memory singleton that persists throughout the app session.
 * acts as a primary buffer against Telegram's aggressive localStorage clearing on iOS.
 */
class SessionArchive {
  private history: Map<string, LexicalEntry> = new Map();
  private suggestions: Map<string, string[]> = new Map();
  private profile: UserProfile | null = null;
  private globalEntries: Map<string, LexicalEntry> = new Map();

  setProfile(p: UserProfile) { this.profile = p; }
  getProfile() { return this.profile; }

  addToHistory(entry: LexicalEntry) {
    const key = `${entry.term.toLowerCase()}:${entry.sourceLang}:${entry.targetLang}`;
    this.history.set(key, entry);
  }
  getHistory() { 
    return Array.from(this.history.values()).sort((a, b) => b.timestamp - a.timestamp); 
  }

  setGlobalEntry(key: string, entry: LexicalEntry) { this.globalEntries.set(key, entry); }
  getGlobalEntry(key: string) { return this.globalEntries.get(key); }

  setSuggestions(key: string, list: string[]) { this.suggestions.set(key, list); }
  getSuggestions(key: string) { return this.suggestions.get(key); }

  clear() {
    this.history.clear();
    this.suggestions.clear();
    this.globalEntries.clear();
    this.profile = null;
  }
}

export const sessionArchive = new SessionArchive();

const handleSupabaseError = (error: any, tableName: string) => {
  if (!error) return false;
  const isMissing = error.code === 'PGRST204' || error.code === 'PGRST205' || error.status === 404;
  if (isMissing) return true;
  console.error(`Supabase Error [${tableName}]:`, error);
  return false;
};

export async function fetchAdminUsers() {
  try {
    const { data: usersData, error: usersError } = await supabase
      .from('users')
      .select('username, first_name, created_at')
      .order('created_at', { ascending: false });

    if (!usersError) return usersData || [];
    if (handleSupabaseError(usersError, 'users')) {
      const { data: profileData } = await supabase
        .from('lex_profiles')
        .select('username, updated_at')
        .order('updated_at', { ascending: false });
      return (profileData || []).map(p => ({
        username: p.username,
        first_name: p.username || 'Scholar',
        created_at: p.updated_at
      }));
    }
    return [];
  } catch { return []; }
}

export async function fetchAdminStats() {
  try {
    const [profiles, entries, history, recent, userList] = await Promise.all([
      supabase.from('lex_profiles').select('*', { count: 'exact', head: true }),
      supabase.from('lex_entries').select('*', { count: 'exact', head: true }),
      supabase.from('lex_user_history').select('*', { count: 'exact', head: true }),
      supabase.from('lex_entries').select('term, source_lang, target_lang, created_at').order('created_at', { ascending: false }).limit(10),
      fetchAdminUsers()
    ]);
    return {
      totalUsers: profiles.count || 0,
      totalEntries: entries.count || 0,
      totalHistory: history.count || 0,
      recentActivity: recent.data || [],
      users: userList
    };
  } catch {
    return { totalUsers: 0, totalEntries: 0, totalHistory: 0, recentActivity: [], users: [] };
  }
}

export async function fetchSuggestions(query: string, sourceLang: Language): Promise<string[]> {
  const cleanQuery = query.toLowerCase().trim();
  if (cleanQuery.length < 2) return [];
  const cacheKey = `${sourceLang}:${cleanQuery}`;
  const cached = sessionArchive.getSuggestions(cacheKey);
  if (cached) return cached;

  try {
    const { data } = await supabase
      .from('lex_entries')
      .select('term')
      .eq('source_lang', sourceLang)
      .ilike('normalized_term', `${cleanQuery}%`)
      .limit(8);
    const results = Array.from(new Set((data || []).map(d => d.term))) as string[];
    sessionArchive.setSuggestions(cacheKey, results);
    return results;
  } catch { return []; }
}

export async function fetchGlobalEntry(
  normalizedTerm: string,
  sourceLang: Language,
  targetLang: Language
): Promise<LexicalEntry | null> {
  const cacheKey = `${normalizedTerm}:${sourceLang}:${targetLang}`;
  const cached = sessionArchive.getGlobalEntry(cacheKey);
  if (cached) return cached;

  try {
    const { data } = await supabase
      .from('lex_entries')
      .select('entry_data')
      .eq('normalized_term', normalizedTerm)
      .eq('source_lang', sourceLang)
      .eq('target_lang', targetLang)
      .maybeSingle();
    if (!data) return null;
    const entry = data.entry_data as LexicalEntry;
    sessionArchive.setGlobalEntry(cacheKey, entry);
    return entry;
  } catch { return null; }
}

export async function saveGlobalEntry(entry: LexicalEntry) {
  try {
    await supabase.from('lex_entries').upsert({
      term: entry.term,
      normalized_term: entry.normalizedTerm,
      source_lang: entry.sourceLang,
      target_lang: entry.targetLang,
      entry_data: entry,
      created_at: new Date().toISOString()
    }, { onConflict: 'normalized_term, source_lang, target_lang' });
    sessionArchive.setGlobalEntry(`${entry.normalizedTerm}:${entry.sourceLang}:${entry.targetLang}`, entry);
  } catch {}
}

export async function fetchProfile(telegramId: number): Promise<UserProfile | null> {
  try {
    const { data } = await supabase
      .from('lex_profiles')
      .select('profile_data')
      .eq('telegram_id', telegramId)
      .maybeSingle();
    if (!data) return null;
    const profile = data.profile_data as UserProfile;
    sessionArchive.setProfile(profile);
    return profile;
  } catch { return null; }
}

export async function fetchUserHistory(telegramId: number): Promise<LexicalEntry[]> {
  try {
    const { data } = await supabase
      .from('lex_user_history')
      .select('entry_data')
      .eq('telegram_id', telegramId)
      .order('created_at', { ascending: false })
      .limit(50);
    const entries = (data || []).map(d => d.entry_data as LexicalEntry);
    entries.forEach(e => sessionArchive.addToHistory(e));
    return entries;
  } catch { return []; }
}

export async function saveUserHistoryEntry(telegramId: number, entry: LexicalEntry) {
  try {
    sessionArchive.addToHistory(entry);
    await supabase.from('lex_user_history').upsert({
      telegram_id: telegramId,
      entry_id: entry.id,
      entry_data: entry,
      created_at: new Date().toISOString()
    }, { onConflict: 'telegram_id, entry_id' });
  } catch {}
}

export async function upsertProfile(profile: UserProfile) {
  if (!profile.telegramId) return;
  sessionArchive.setProfile(profile);
  try {
    supabase.from('users').upsert({
      telegram_id: profile.telegramId,
      username: profile.username || 'Scholar',
      first_name: profile.firstName || '',
      last_name: profile.lastName || '',
      updated_at: new Date().toISOString()
    }, { onConflict: 'telegram_id' });

    await supabase.from('lex_profiles').upsert({ 
      telegram_id: profile.telegramId,
      username: profile.username || 'Scholar',
      profile_data: profile,
      updated_at: new Date().toISOString() 
    }, { onConflict: 'telegram_id' });
  } catch {}
}

