import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { AppMode, LexicalEntry, UserProfile } from './types';
import Dictionary from './components/Dictionary';
import Arena from './components/Arena';
import Archive from './components/Archive';
import AdminPanel from './components/AdminPanel';
import { RANKS, ADMIN_ID } from './constants';
import { 
  fetchProfile, 
  upsertProfile, 
  fetchUserHistory, 
  saveUserHistoryEntry,
  sessionArchive 
} from './services/supabase';
import { 
  getTelegramUser,
  initTelegramTheme, 
  openTelegramLink,
  triggerHaptic
} from './services/telegram';
import { resumeAudioContext } from './services/tts';

// Main Application Component
const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>(AppMode.DICTIONARY);
  const [history, setHistory] = useState<LexicalEntry[]>([]);
  const [profile, setProfile] = useState<UserProfile>({
    username: 'Scholar',
    xp: 0,
    rank: 'Lexical Novice',
    searchCount: 0,
    arenaWins: 0,
    accuracy: 100,
    streak: 0
  });
  const [autoAudio, setAutoAudio] = useState(true);
  const [selectedEntry, setSelectedEntry] = useState<LexicalEntry | null>(null);

  // Initialize App and load user data from Telegram context or session
  useEffect(() => {
    initTelegramTheme();
    const user = getTelegramUser();
    if (user) {
      loadUserData(user.id);
    } else {
      const h = sessionArchive.getHistory();
      if (h.length > 0) setHistory(h);
    }
  }, []);

  const loadUserData = async (tgId: number) => {
    const p = await fetchProfile(tgId);
    if (p) setProfile(p);

    const h = await fetchUserHistory(tgId);
    if (h && h.length > 0) {
      setHistory(h);
    }
  };

  const handleEntrySaved = useCallback(async (entry: LexicalEntry) => {
    setHistory(prev => {
      const filtered = prev.filter(e => e.id !== entry.id);
      return [entry, ...filtered];
    });

    const user = getTelegramUser();
    if (user) {
      await saveUserHistoryEntry(user.id, entry);

      const newXp = profile.xp + 15;
      const currentRank = RANKS.reduce((prev, curr) => newXp >= curr.minXp ? curr : prev, RANKS[0]);

      const newProfile: UserProfile = { 
        ...profile, 
        xp: newXp,
        rank: currentRank.title,
        searchCount: (profile.searchCount || 0) + 1 
      };

      setProfile(newProfile);
      await upsertProfile(newProfile);
    }
  }, [profile]);

  const handleQuizResult = useCallback(async (score: number, total: number) => {
    const xpGained = score * 5;
    const newXp = profile.xp + xpGained;
    const currentRank = RANKS.reduce((prev, curr) => newXp >= curr.minXp ? curr : prev, RANKS[0]);

    const newProfile: UserProfile = {
      ...profile,
      xp: newXp,
      rank: currentRank.title,
      arenaWins: profile.arenaWins + (score === total && total > 0 ? 1 : 0),
      accuracy: total > 0 
        ? Math.round(((profile.accuracy * profile.searchCount) + (score/total * 100)) / (profile.searchCount + 1))
        : profile.accuracy
    };

    setProfile(newProfile);
    const user = getTelegramUser();
    if (user) {
      await upsertProfile(newProfile);
    }
  }, [profile]);

  const isAdmin = useMemo(() => {
    const user = getTelegramUser();
    return user?.id === ADMIN_ID;
  }, []);

  const handleEntryClick = (entry: LexicalEntry) => {
    setSelectedEntry(entry);
    setMode(AppMode.DICTIONARY);
    triggerHaptic('light');
  };

  return (
    <div className="min-h-screen bg-[#fcfcfb] text-stone-900 selection:bg-[#7c1a1a]/10 selection:text-[#7c1a1a]">
      {/* Navigation */}
      <nav className="sticky top-0 z-50 bg-[#fcfcfb]/80 backdrop-blur-md border-b border-stone-100 px-6 py-4">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <div 
            className="flex items-center gap-3 cursor-pointer" 
            onClick={() => { setMode(AppMode.DICTIONARY); setSelectedEntry(null); }}
          >
            <div className="w-8 h-8 bg-[#7c1a1a] flex items-center justify-center text-white font-black serif text-xs">LEX.</div>
            <span className="hidden sm:inline text-[10px] uppercase tracking-[0.4em] font-black text-stone-400">Philological Portal</span>
          </div>

          <div className="flex items-center gap-4 sm:gap-8">
            <button 
              onClick={() => { setMode(AppMode.DICTIONARY); setSelectedEntry(null); triggerHaptic('light'); }}
              className={`text-[10px] uppercase tracking-[0.3em] font-black transition-all ${mode === AppMode.DICTIONARY ? 'text-[#7c1a1a]' : 'text-stone-400 hover:text-stone-600'}`}
            >
              Lexicon
            </button>
            <button 
              onClick={() => { setMode(AppMode.ARENA); triggerHaptic('light'); }}
              className={`text-[10px] uppercase tracking-[0.3em] font-black transition-all ${mode === AppMode.ARENA ? 'text-[#7c1a1a]' : 'text-stone-400 hover:text-stone-600'}`}
            >
              Arena
            </button>
            <button 
              onClick={() => { setMode(AppMode.ARCHIVE); triggerHaptic('light'); }}
              className={`text-[10px] uppercase tracking-[0.3em] font-black transition-all ${mode === AppMode.ARCHIVE ? 'text-[#7c1a1a]' : 'text-stone-400 hover:text-stone-600'}`}
            >
              Archive
            </button>
            {isAdmin && (
              <button 
                onClick={() => { setMode(AppMode.ADMIN); triggerHaptic('heavy'); }}
                className={`text-[10px] uppercase tracking-[0.3em] font-black transition-all ${mode === AppMode.ADMIN ? 'text-[#7c1a1a]' : 'text-stone-400 hover:text-stone-600'}`}
              >
                Ledger
              </button>
            )}
          </div>
        </div>
      </nav>

      <main className="px-6 pb-20">
        <div className="max-w-7xl mx-auto pt-10">
