export const normalizeQuery = (text: string, lang?: string): string => {
  if (!text) return "";

  // 1. Unicode Normalization (NFC) - MANDATORY for iOS NFD (decomposed) compatibility
  // This ensures that 'e' + '´' (NFD) becomes 'é' (NFC) before any processing or lookup.
  let res = text.normalize('NFC');

  // 2. Aggressively strip non-visible/control/zero-width characters (iOS artifacts)
  // These often break JSON.parse or DB equality checks.
  res = res.replace(/[\u0000-\u001F\u007F-\u009F\u200B-\u200D\u2028\u2029\uFEFF]/g, "");

  // 3. Normalize "Smart" Punctuation (iOS Default)
  res = res
    .replace(/[\u2018\u2019\u201A\u201B\u2032\u2035\u02BB\u02BC]/g, "'") 
    .replace(/[\u201C\u201D\u201E\u201F\u2033\u2036]/g, '"')
    .replace(/\u2013/g, "-")
    .replace(/\u2014/g, "--")
    .replace(/[\u00A0\u202F]/g, " ");

  // 4. Case and Trim
  res = res.trim().toLowerCase();

  // 5. Philological Normalization (Language Specific)
  if (lang === 'German') {
    res = res
      .replace(/ä/g, 'ae')
      .replace(/ö/g, 'oe')
      .replace(/ü/g, 'ue')
      .replace(/ß/g, 'ss');
  } else if (lang === 'Uzbek') {
    res = res.replace(/[‘’`‘]/g, "'");
  }

  return res.trim();
};

