const generateId = () => {
  try {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
      return crypto.randomUUID();
    }
  } catch (e) {}
  return 'lex-' + Date.now() + '-' + Math.random().toString(36).substring(2, 11);
};

/**
 * Enhanced JSON cleaning specifically for iOS Safari.
 * Removes hidden characters and normalizes typographic quotes that break JSON.parse.
 */
function cleanJsonResponse(text: string): string {
  if (!text || typeof text !== 'string') return "{}";

  let cleaned = text.trim();

  // Remove markdown code blocks
  if (cleaned.startsWith("```")) {
    cleaned = cleaned.replace(/^```[a-zA-Z]*\n?/, "").replace(/\n?```$/, "");
  }

  // Extract content between first and last braces/brackets
  const firstBrace = cleaned.indexOf('{');
  const lastBrace = cleaned.lastIndexOf('}');
  const firstBracket = cleaned.indexOf('[');
  const lastBracket = cleaned.lastIndexOf(']');

  let start = -1;
  let end = -1;

  if (firstBrace !== -1 && (firstBracket === -1 || (firstBrace < firstBracket && firstBrace !== -1))) {
    start = firstBrace;
    end = lastBrace;
  } else if (firstBracket !== -1) {
    start = firstBracket;
  }

  if (start !== -1 && end !== -1 && end > start) {
    cleaned = cleaned.substring(start, end + 1);
  }

  // CRITICAL FOR IOS: Remove non-printable control characters that sneak into LLM output
  cleaned = cleaned.replace(/[\u0000-\u001F\u007F-\u009F\uFEFF\u200B-\u200D\u2028\u2029]/g, "");

  // Normalize smart quotes to standard JSON quotes
  cleaned = cleaned.replace(/[\u201C\u201D\u201E\u201F\u2033\u2036]/g, '"')
                   .replace(/[\u2018\u2019\u201A\u201B\u2032\u2035]/g, "'");

  return cleaned.trim();
}

export async function translateWordCore(
  query: string, 
  sourceLanguage: Language, 
  targetLanguage: Language
): Promise<LexicalEntry> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `System: Philological Lexicon. 
Task: Analyze and translate "${query}" from ${sourceLanguage} to ${targetLanguage}.
STRICT LANGUAGE CONSTRAINTS:
- Primary translation in ${targetLanguage}.
- Synonyms in ${sourceLanguage}.
- Semantic variations in ${targetLanguage}.
Output: JSON ONLY.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            term: { type: Type.STRING },
            mainTranslation: { type: Type.STRING },
            partOfSpeech: { type: Type.STRING },
            gender: { type: Type.STRING },
            plural: { type: Type.STRING },
            cefrLevel: { type: Type.STRING },
            synonyms: { type: Type.ARRAY, items: { type: Type.STRING } },
            variations: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  confidence: { type: Type.NUMBER }
                }
              }
            }
          },
          required: ["term", "mainTranslation", "partOfSpeech"]
        }
      }
    });

    const cleaned = cleanJsonResponse(response.text || "{}");
    const rawData = JSON.parse(cleaned);

    return {
      id: generateId(),
      term: rawData.term || query,
      normalizedTerm: normalizeQuery(rawData.term || query, sourceLanguage),
      mainTranslation: rawData.mainTranslation || "No translation found",
      sourceLang: sourceLanguage,
      targetLang: targetLanguage,
      cefrLevel: sourceLanguage !== 'Uzbek' ? rawData.cefrLevel : undefined,
      philology: {
        etymology: "", 
        partOfSpeech: rawData.partOfSpeech || "n/a",
        gender: rawData.gender,
        plural: rawData.plural
      },
      culture: { usage: "", register: 'neutral', notes: "" },
      synonyms: rawData.synonyms || [],
      variations: (rawData.variations || []).map((v: any) => ({ ...v, source: 'ai' })),
      literature: [],
      realLifeSentences: [],
      idioms: [],
      timestamp: Date.now()
    };
  } catch (err: any) {
    console.error("Philological Retrieval Core Error:", err);
    throw err;
  }
}

