    try {
      const p = await fetchProfile(tgId);
      if (p) setProfile(p);

      const h = await fetchUserHistory(tgId);
      if (h && h.length > 0) {
        setHistory(h);
      }
    } catch (err) {
      console.warn("Hydration restricted by iOS environment. Falling back to session memory.");
      const h = sessionArchive.getHistory();
      if (h.length > 0) setHistory(h);
    }
  };

  const handleEntrySaved = useCallback(async (entry: LexicalEntry) => {
    setHistory(prev => {
